import { Center, Flex, Heading, Spinner } from '@chakra-ui/react';
import { useGetAccount, useUpdateAccount } from '@state/accounts';
import { Button, ClipboardButton } from '@ui/components/Button';
import { Loading } from '@ui/components/Loading';
import { Panel } from '@ui/components/Panel';
import { Paragraph } from '@ui/components/typography';
import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { generatePath, Navigate } from 'react-router-dom';
import { useOrganizationApplicationStore } from '../OrganizationApplicationContext';
import { useSteps } from '../useSteps';
import { ApplicationSummary } from './ApplicationSummary';

export function SubmitApplication() {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'submitApplication' });
  const { currentAccount } = useGetAccount();
  const { isLoading, submitAccount } = useUpdateAccount();
  // In the small steps nav, this will show the errors for steps that are not complete
  const { setShowPendingStepsAsErrors } = useOrganizationApplicationStore();
  const { steps } = useSteps();
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [validateState, setValidateState] = useState<'valid' | 'invalid' | 'pending' | 'loading'>(
    'pending'
  );
  const isValidated = validateState === 'valid';

  const hasAcceptedFinancialAuthority =
    steps.find((step) => step.path === 'financial_authority')?.status === 'complete';

  const clipboardValue =
    window.location.origin +
    generatePath('/accounts/:accountId/application/financial_authority', {
      accountId: currentAccount?.id ?? '',
    });

  const onSubmitApplication = () => {
    const hasIncompleteSteps = steps
      .filter((step) => step.path !== 'submit_application')
      .find((step) => step.status !== 'complete');

    if (hasIncompleteSteps) {
      setShowPendingStepsAsErrors(true);
      setValidateState('invalid');
    } else {
      setIsSubmitting(true);
      submitAccount({});
    }
  };

  const handleValidateClick = () => {
    setValidateState('loading');
    const hasIncompleteSteps = steps
      .filter((step) => step.path !== 'submit_application')
      .find((step) => step.status !== 'complete');

    // fake the long validation call for now
    const fakeValidationTimeout = setTimeout(() => {
      if (hasIncompleteSteps) {
        setShowPendingStepsAsErrors(true);
        setValidateState('invalid');
      } else {
        setValidateState('valid');
      }
    }, 1000);
    return () => clearTimeout(fakeValidationTimeout);
  };

  if (!currentAccount) {
    return (
      <Center height="100vh">
        <Loading />
      </Center>
    );
  }

  if (currentAccount?.status === 'pending' || currentAccount?.status === 'disabled') {
    // Account status is updated to 'pending' upon successful submission
    if (isSubmitting) {
      setIsSubmitting(false);
    }
    return <Navigate replace to={`/accounts/${currentAccount.id}/application/status`} />;
  }

  return (
    <>
      <hgroup>
        <Heading as="h1">{t('heading')}</Heading>
        <Paragraph as="h2">{currentAccount?.displayName}</Paragraph>
      </hgroup>
      <Panel display="flex" flexDirection="column" gap={6} p={6} variant="primary">
        {currentAccount && <ApplicationSummary account={currentAccount} steps={steps} />}
        <Flex direction="column" gap={3}>
          <Paragraph>{t('paragraphs.one')}</Paragraph>
          <Paragraph>{t('paragraphs.two')}</Paragraph>
        </Flex>
        {!hasAcceptedFinancialAuthority && (
          <Flex bgColor="red.100" borderRadius="md" direction="column" gap={5} p={5}>
            <Paragraph>{t('warnings.financialAuthority')}</Paragraph>
            <ClipboardButton side="left" value={clipboardValue} variant="secondary">
              {t('warnings.financialAuthorityAction')}
            </ClipboardButton>
          </Flex>
        )}
        <Flex direction="row" gap={3}>
          <Button
            isDisabled={
              validateState === 'valid' || validateState === 'loading' || isLoading || isSubmitting
            }
            isLoading={isLoading || isSubmitting}
            onClick={handleValidateClick}
            size="lg"
            w="full"
            variant={isValidated ? 'secondary' : 'primary'}
          >
            {validateState === 'loading' && <Spinner size="sm" color="white" />}
            {validateState === 'valid' && 'Ready to Submit!'}
            {validateState === 'invalid' && 'Errors found - Revalidate'}
            {validateState === 'pending' && 'Run Final Check'}
          </Button>
          <Button
            isDisabled={isLoading || isSubmitting || !isValidated}
            isLoading={isLoading || isSubmitting}
            onClick={onSubmitApplication}
            size="lg"
            w="full"
          >
            {t('action')}
          </Button>
        </Flex>
      </Panel>
    </>
  );
}

