import { StringRecord } from '@i18n/types';
import { screen } from '@testing-library/react';
import { expect } from 'vitest';
import { getStringIds } from './getStringIds';

// This file relies on explicitly imported `expect` from vitest.
// stringsJest is duplicate but uses global `expect`

export const verifyString = async (stringToFind: string) => {
  // using findAllByText due to occasionally the same text showing up (e.g. Public Address)
  // This isn't a "perfect" approach, but gives us a quick way to check presence of
  // text in doc without needing to specify every element by data-testid or other approach
  const elements = await screen.findAllByText(stringToFind);

  expect(elements[0]).toBeInTheDocument();
};

/**
 * verify string is not in the document
 */
export const notVerifyString = (text: string) => {
  expect(screen.queryByText(text)).not.toBeInTheDocument();
};

/**
 * verify string is visible
 */
export const isVisibleString = async (stringToFind: string) => {
  const el = await screen.findByText(stringToFind);
  expect(el).toBeInTheDocument();
};

/**
 * verify string is not visible
 */
export const isNotVisibleString = (text: string) => {
  expect(screen.queryByText(text)).not.toBeVisible();
};

export const verifyPlaceholderString = async (stringToFind: string) => {
  // findAllByText in verify String does only search for text content, but doesn't look for placeholder
  const elements = await screen.findAllByPlaceholderText(stringToFind);

  expect(elements[0]).toBeInTheDocument();
};

/**
 * Verify that the paths defined by the provided @StringRecord exist in the document
 *
 * @param strings @StringRecord
 * @param path optional path to filter by (i.e. 'view.button')
 */
export const verifyStringRecord = async (
  strings: StringRecord,
  path?: string,
  ignore?: string,
  prefix?: string
) => {
  const stringIds = getStringIds(strings).filter(
    (p) => !path || (p.indexOf(`${path}.`) === 0 && (!ignore || p.indexOf(ignore) < 0))
  );

  for (let i = 0; i < stringIds.length; i++) {
    await verifyString(stringIds[i].replace(prefix ? `${prefix}.` : '', ''));
  }
};

